        if tuple(A.shape) != (2048, 8192) or tuple(B.shape) != (4096, 8192):
            return torch.matmul(A, B.T)
        A2 = A.contiguous()
        B2 = B.transpose(-2, -1).contiguous()
        C = torch.empty((2048, 4096), device=A.device, dtype=A.dtype)
        gemm_kernel[lambda: ((1, 1, 1), (1, 1, 1))](A2, B2, C)
